const all = $input.all();

// ── 최저/최고 기온 + 하늘상태 ─────────────────────────────────────────
const low_temperature  = all[0].json.low_temperature;
const high_temperature = all[0].json.high_temperature;
const sky              = all[0].json.sky;

// ── 초단기실황 ──────────────────────────────────────────────────────
const realtimeRaw = all[1].json.response?.body?.items?.item;
const realtimeItems = Array.isArray(realtimeRaw) ? realtimeRaw : (realtimeRaw ? [realtimeRaw] : []);

const realtime = {};
realtimeItems.forEach(item => { realtime[item.category] = item.obsrValue; });

// ── 미세먼지 ────────────────────────────────────────────────────────
const dust = all[2].json.response?.body?.items?.[0];

// ── 코드 매핑 ────────────────────────────────────────────────────────
const ptyCode  = { '0': '없음', '1': '비', '2': '비/눈', '3': '눈', '4': '소나기' };
const gradeMap = { '1': '좋음', '2': '보통', '3': '나쁨', '4': '매우나쁨' };

return [{
  temperature:     realtime['T1H']  ?? '알 수 없음',
  low_temperature,
  high_temperature,
  sky,
  rain:            ptyCode[realtime['PTY']] ?? '없음',
  humidity:        realtime['REH']  ?? '알 수 없음',
  windSpeed:       realtime['WSD']  ?? '알 수 없음',
  pm25:            dust?.pm25Value  ?? '알 수 없음',
  pm10:            dust?.pm10Value  ?? '알 수 없음',
  pm25_grade:      gradeMap[dust?.pm25Grade]  ?? '알 수 없음',
  pm10_grade:      gradeMap[dust?.pm10Grade]  ?? '알 수 없음',
}];

const items = $input.first().json.response?.body?.items?.item;
const forecastItems = Array.isArray(items) ? items : (items ? [items] : []);

const today = forecastItems[0]?.fcstDate;

let low_temperature  = '알 수 없음';
let high_temperature = '알 수 없음';
let sky = '알 수 없음';

const skyCode = { '1': '맑음', '3': '구름많음', '4': '흐림' };

forecastItems.forEach(item => {
  if (item.fcstDate !== today) return;
  if (item.category === 'TMN') low_temperature  = item.fcstValue;
  if (item.category === 'TMX') high_temperature = item.fcstValue;
  if (item.category === 'SKY' && sky === '알 수 없음') sky = skyCode[item.fcstValue] ?? '알 수 없음';
});

return [{ low_temperature, high_temperature, sky }];

const body = $input.first().json.body || $input.first().json;
const message = body.message || '';
const userId = body.user_id || '';
const location = body.location || '탕정';

const stopwords = new Set([
  '나','저','좀','을','를','이','가','은','는','에','의','도','로','으로',
  '와','과','먹고','싶어','싶은데','먹을까','추천','해줘','해줘요','어때',
  '뭐','있어','없어','가고','가자','정도','그냥','오늘','어디','뭔가',
  '하고','싶다','할래','갈래','볼래','먹자','주세요','부탁'
]);

const words = message
  .replace(/[?!.,~]/g, '')
  .split(/\s+/)
  .filter(w => w.length >= 2 && !stopwords.has(w));

const primaryKeyword = words[0] || message.slice(0, 5);

return [{ json: {
