const items = $input.all()
const logit_map = {}, updated_at_map = {}

items.forEach(item => {
  const { category, logit, updated_at } = item.json
  if (category) {
    logit_map[category]      = logit ?? 0
    updated_at_map[category] = updated_at ?? null
  }
})

return [{ json: { logit_map, updated_at_map } }]

const T = 1.5, EPS = 0.10, GAMMA = 0.95, K = 7
const CATS = ['한식', '중식', '양식', '분식', '일식', '디저트', '기타']

const logitData    = $('로짓 집계').first().json
const logitMap     = logitData.logit_map      || {}
const updatedAtMap = logitData.updated_at_map || {}

const today = new Date()
const effectiveLogits = {}
CATS.forEach(cat => {
  const daysSince = updatedAtMap[cat]
    ? (today.getTime() - new Date(updatedAtMap[cat]).getTime()) / 86400000 : 0
  effectiveLogits[cat] = (logitMap[cat] ?? 0) * Math.pow(GAMMA, daysSince)
})

let expSum = 0
const expMap = {}
CATS.forEach(cat => {
  expMap[cat] = Math.exp((effectiveLogits[cat] || 0) / T)
  expSum += expMap[cat]
})

const probs = {}
CATS.forEach(cat => {
  probs[cat] = (1 - EPS) * (expMap[cat] / expSum) + EPS / K
})

const restaurants = $input.first().json.restaurants || []
const sorted = [...restaurants]
  .map(r => ({ ...r, _score: probs[r.category || '기타'] || (EPS / K) }))
  .sort((a, b) => b._score - a._score)

return [{ json: { restaurants: sorted } }]

const raw  = $('월드컵 입력').first().json
const body = raw.body || raw
const { user_id, champion = '', rounds = [] } = body

const CATS = ['한식', '중식', '양식', '분식', '일식', '디저트', '기타']

const currentMap = {}
$input.all().forEach(item => {
  if (item.json.category) {
    currentMap[item.json.category] = {
      logit:        item.json.logit        ?? 0,
      sample_count: item.json.sample_count ?? 0
    }
  }
})

const deltaMap = {}
CATS.forEach(c => { deltaMap[c] = 0 })
rounds.forEach(r => {
  if (r.winner_category && deltaMap[r.winner_category] !== undefined)
    deltaMap[r.winner_category] += 0.3
  if (r.loser_category && deltaMap[r.loser_category] !== undefined)
    deltaMap[r.loser_category] -= 0.1
})

const now = new Date().toISOString()

const categories_to_upsert = CATS.map(cat => ({
  user_id,
  category:     cat,
  logit:        Math.max(-10, Math.min(10, Math.round(((currentMap[cat]?.logit ?? 0) + (deltaMap[cat] || 0)) * 1000) / 1000)),
  sample_count: (currentMap[cat]?.sample_count ?? 0) + 1,
  updated_at:   now,
  exists:       !!currentMap[cat]
}))

const T = 1.5, EPS = 0.1, K = 7
let expSum = 0
const expMap = {}
categories_to_upsert.forEach(c => {
  expMap[c.category] = Math.exp(c.logit / T)
  expSum += expMap[c.category]
})

const top_categories = Object.entries(expMap)
  .map(([cat, exp]) => ({ cat, p: (1 - EPS) * exp / expSum + EPS / K }))
  .sort((a, b) => b.p - a.p)
  .slice(0, 3)
  .map(e => e.cat)

return [{
  json: { user_id, champion, rounds, top_categories, categories_to_upsert, created_at: now }
}]

const Imap = require('imap');
const { simpleParser } = require('mailparser');

const provider = $('Edit Fields1').item.json.email_provider;
const address  = $('Edit Fields1').item.json.email_address;
const password = $('Edit Fields1').item.json.email_app_pw;

const hostMap = {
  naver: 'imap.naver.com',
  gmail: 'imap.gmail.com',
};
const host = hostMap[provider] ?? 'imap.naver.com';

return new Promise((resolve, reject) => {
  const imap = new Imap({ user: address, password, host, port: 993, tls: true });
  const mails = [];

  imap.once('ready', () => {
    imap.openBox('INBOX', true, (err) => {
      if (err) { imap.end(); return reject(err); }

      imap.search(['UNSEEN'], (err, uids) => {
        if (err || !uids.length) {
          imap.end();
          return resolve([{ json: { mails: [] } }]);
        }

        const recent = uids.slice(-5);
        const f = imap.fetch(recent, { bodies: '' });

        let pending = 0;
        let fetchEnded = false;

        f.on('message', msg => {
          pending++;
          msg.on('body', stream => {
            simpleParser(stream, (err, parsed) => {
              if (!err) mails.push({
                from:    parsed.from?.text ?? '',
                subject: parsed.subject ?? '',
                text:    (parsed.text ?? '').slice(0, 300),
              });
              pending--;
              if (pending === 0 && fetchEnded) imap.end();
            });
          });
        });

        f.once('end', () => {
          fetchEnded = true;
          if (pending === 0) imap.end();
        });
      });
    });
  });

  imap.once('end',   () => resolve([{ json: { mails } }]));
  imap.once('error', reject);
  imap.connect();
});

const data = $('월드컵 로직 계산').first().json
return [{
