const doc = $input.first().json.documents[0];
const lat = parseFloat(doc.y);
const lon = parseFloat(doc.x);
const today = $now.toFormat('yyyy-MM-dd');

// 시도명 직접 추출
const sido = doc.address.region_1depth_name;

// 기상청 격자 변환 공식 (WGS84 → nx/ny)
const RE = 6371.00877;
const GRID = 5.0;
const SLAT1 = 30.0;
const SLAT2 = 60.0;
const OLON = 126.0;
const OLAT = 38.0;
const XO = 43;
const YO = 136;
const DEGRAD = Math.PI / 180.0;
const re = RE / GRID;
const slat1 = SLAT1 * DEGRAD;
const slat2 = SLAT2 * DEGRAD;
const olon = OLON * DEGRAD;
const olat = OLAT * DEGRAD;
let sn = Math.tan(Math.PI * 0.25 + slat2 * 0.5) / Math.tan(Math.PI * 0.25 + slat1 * 0.5);
sn = Math.log(Math.cos(slat1) / Math.cos(slat2)) / Math.log(sn);
let sf = Math.tan(Math.PI * 0.25 + slat1 * 0.5);
sf = Math.pow(sf, sn) * Math.cos(slat1) / sn;
let ro = Math.tan(Math.PI * 0.25 + olat * 0.5);
ro = re * sf / Math.pow(ro, sn);
const ra = Math.tan(Math.PI * 0.25 + lat * DEGRAD * 0.5);
const raVal = re * sf / Math.pow(ra, sn);
let theta = lon * DEGRAD - olon;
if (theta > Math.PI) theta -= 2.0 * Math.PI;
if (theta < -Math.PI) theta += 2.0 * Math.PI;
theta *= sn;
const nx = Math.floor(raVal * Math.sin(theta) + XO + 0.5);
const ny = Math.floor(ro - raVal * Math.cos(theta) + YO + 0.5);

// 날짜 형식 변환
const baseDate = today.replace(/-/g, '');

// 전날 날짜 계산
const yesterdayDate = new Date(today);
yesterdayDate.setDate(yesterdayDate.getDate() - 1);
const yesterday = yesterdayDate.getFullYear().toString() +
  String(yesterdayDate.getMonth() + 1).padStart(2, '0') +
  String(yesterdayDate.getDate()).padStart(2, '0');

// WGS84 → TM 좌표 변환
const toRad = d => d * Math.PI / 180;
const a = 6378137.0;
const f = 1 / 298.257222101;
const b = a * (1 - f);
const e2 = 1 - (b * b) / (a * a);
const e = Math.sqrt(e2);
const k0 = 1.0;
const lon0 = toRad(127.0028902777778);
const lat0 = toRad(38.0);
const FE = 200000.0;
const FN = 500000.0;
const latR = toRad(lat);
const lonR = toRad(lon);
const N = a / Math.sqrt(1 - e2 * Math.sin(latR) ** 2);
const T = Math.tan(latR) ** 2;
const C = (e2 / (1 - e2)) * Math.cos(latR) ** 2;
const A = Math.cos(latR) * (lonR - lon0);
const M = a * (
  (1 - e2/4 - 3*e2**2/64) * latR
  - (3*e2/8 + 3*e2**2/32) * Math.sin(2*latR)
  + (15*e2**2/256) * Math.sin(4*latR)
);
const M0 = a * (
  (1 - e2/4 - 3*e2**2/64) * lat0
  - (3*e2/8 + 3*e2**2/32) * Math.sin(2*lat0)
  + (15*e2**2/256) * Math.sin(4*lat0)
);
const tmX = FE + k0 * N * (A + (1-T+C)*A**3/6);
const tmY = FN + k0 * (M - M0 + N*Math.tan(latR)*(A**2/2 + (5-T+9*C)*A**4/24));

return [{
  nx,
  ny,
  baseDate,
  yesterday,
  lat,
  lon,
  sido,
  tmX: Math.round(tmX),
  tmY: Math.round(tmY)
}];
